// BFS OpenCL kernels

typedef struct {
    int starting;
    int no_of_edges;
} Node;

// Kernel 1: Process active nodes and update their neighbors
__kernel void BFS_1(__global const Node* graph_nodes,
                    __global const int* graph_edges,
                    __global char* graph_mask,
                    __global char* updating_graph_mask,
                    __global const char* graph_visited,
                    __global int* cost,
                    int no_of_nodes)
{
    int tid = get_global_id(0);

    if (tid < no_of_nodes) {
        if (graph_mask[tid] == 1) {
            graph_mask[tid] = 0;
            int start = graph_nodes[tid].starting;
            int num_edges = graph_nodes[tid].no_of_edges;

            for (int i = start; i < start + num_edges; i++) {
                int neighbor = graph_edges[i];
                if (graph_visited[neighbor] == 0) {
                    cost[neighbor] = cost[tid] + 1;
                    updating_graph_mask[neighbor] = 1;
                }
            }
        }
    }
}

// Kernel 2: Update visited status and check if we should continue
__kernel void BFS_2(__global char* graph_mask,
                    __global char* updating_graph_mask,
                    __global char* graph_visited,
                    __global char* over,
                    int no_of_nodes)
{
    int tid = get_global_id(0);

    if (tid < no_of_nodes) {
        if (updating_graph_mask[tid] == 1) {
            graph_mask[tid] = 1;
            graph_visited[tid] = 1;
            *over = 1;
            updating_graph_mask[tid] = 0;
        }
    }
}
